class JavaDocAutoIndentStrategy {
    // Simplified for example
    void computeIndentation(StringBuilder buf) {
        // Simulate the relevant context
        int firstNonWS = 0; // Assume 0 for simplicity
        char[] line = new char[]{'/', '/', '/'};
        if (line[firstNonWS] == '/') {
            if (line[firstNonWS+1] == '/') {
                buf.append("///"); // This is the target match
            } else {
                buf.append(" * ");
            }
        }
    }
}

